module top_module(obf_in, shift, out);input  [7:0] obf_in;
input  [2:0] shift;
output [7:0] out;


	assign out=(shift == 3'b000)? obf_in :
			   (shift == 3'b001)? obf_in<<1 :
			   (shift == 3'b010)? obf_in<<2 :
			   (shift == 3'b011)? obf_in<<3 :
			   (shift == 3'b100)? obf_in<<4 :
			   (shift == 3'b101)? obf_in<<5 :
			   (shift == 3'b110)? obf_in<<6 : obf_in<<7;



endmodule
